format_data:
[{"fieldname":"print_heading_template","fieldtype":"Custom HTML","options":"<div class="print-heading"><h2><div>Weighbridge Invoice</div><br><small class="sub-heading">{{ _(doc.name) }}</small></h2></div>"},{"fieldtype":"Section Break","label":""},{"fieldtype":"Column Break"},{"fieldname":"_custom_html","print_hide":0,"label":"Custom HTML","fieldtype":"HTML","options":"{% set company_doc = frappe.get_doc("Company", doc.company) if doc.company else None %}
{% set customer_tax_id = frappe.db.get_value("Customer", doc.customer, "tax_id") if doc.customer else "" %}
{% set clerk_name = frappe.db.get_value("User", doc.owner, "full_name") if doc.owner else "" %}
{% set wbt = frappe.get_doc("Weighbridge Ticket", doc.weighbridge_ticket) if doc.weighbridge_ticket else None %}

{% set vehicle_no = "" %}
{% if wbt and wbt.vehicle %}
  {% set vehicle_no = frappe.db.get_value("Vehicle", wbt.vehicle, "license_plate") or wbt.vehicle %}
{% endif %}

{% set payment_ref = "" %}
{% if doc.payments and doc.payments|length > 0 %}
  {% set payment_ref = doc.payments[0].reference_no or "" %}
{% endif %}

{% set receipt_number = doc.get("receipt_number") or doc.name %}
{% set destination = doc.shipping_address_name or doc.dispatch_address_name or "" %}

{% set default_tax_rate = 0 %}
{% if doc.taxes and doc.taxes|length > 0 %}
  {% set default_tax_rate = doc.taxes[0].rate or 0 %}
{% endif %}

{% set transport_total = [0.0] %}
{% set product_items = [] %}
{% for item in doc.items %}
  {% set lower_name = ((item.item_name or item.description or item.item_code or "")|lower) %}
  {% if "transport" in lower_name %}
    {% set _ = transport_total.append(transport_total.pop() + (item.amount or 0)) %}
  {% else %}
    {% set _ = product_items.append(item) %}
  {% endif %}
{% endfor %}
{% if product_items|length == 0 %}
  {% set product_items = doc.items %}
{% endif %}

<style>
  .wb-invoice {
    font-size: 11px;
    color: #222;
  }
  .wb-title {
    text-align: center;
    font-weight: 700;
    letter-spacing: 0.3px;
  }
  .wb-subtitle {
    text-align: center;
    margin-top: 2px;
    margin-bottom: 8px;
  }
  .wb-meta {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 8px;
  }
  .wb-meta td {
    padding: 2px 4px;
    vertical-align: top;
  }
  .wb-lines {
    width: 100%;
    border-collapse: collapse;
    margin-top: 8px;
    margin-bottom: 8px;
  }
  .wb-lines th,
  .wb-lines td {
    border-top: 1px solid #666;
    border-bottom: 1px solid #666;
    padding: 4px;
  }
  .wb-lines th {
    text-align: left;
    font-weight: 700;
    white-space: nowrap;
  }
  .wb-right {
    text-align: right;
    white-space: nowrap;
  }
  .wb-total {
    text-align: right;
    margin-top: 8px;
    font-weight: 700;
  }
  .wb-terms {
    margin-top: 12px;
    line-height: 1.45;
  }
</style>

<div class="wb-invoice">
  <div class="wb-title" style="font-size: 24px;">{{ (company_doc.company_name if company_doc else doc.company) or "" }}</div>
  <div class="wb-subtitle">
    VAT No: {{ (company_doc.tax_id if company_doc else "") or "" }}
    {% if company_doc and company_doc.registration_details %}
      / {{ company_doc.registration_details }}
    {% endif %}
  </div>
  <div class="wb-subtitle">{{ frappe.utils.strip_html(doc.company_address_display or "") }}</div>
    <div class="wb-subtitle"><b>{{ doc.doctype }} NO: {{ doc.name }}</b></div>
    <div class="wb-subtitle"><b>{{ _("Tax Invoice") }}</b></div>
  <div class="wb-subtitle">
    Phone No: {{ (company_doc.phone_no if company_doc else "") or "" }}
    {% if company_doc and company_doc.fax %}
      Fax No: {{ company_doc.fax }}
    {% endif %}
  </div>

  <table class="wb-meta">
    <tr>
      <td><b>Client</b></td>
      <td>: {{ doc.customer or "" }} &nbsp; {{ doc.customer_name or "" }}</td>
      <td><b>Date</b></td>
      <td>: {{ frappe.format_value(doc.posting_date, {"fieldtype": "Date"}) }}</td>
    </tr>
    <tr>
      <td><b>VAT / BRN</b></td>
      <td>: {{ customer_tax_id or "" }}</td>
      <td><b>Req./Cheque No</b></td>
      <td>: {{ payment_ref or "" }}</td>
    </tr>
    <tr>
      <td><b>Destination</b></td>
      <td>: {{ destination or "" }}</td>
      <td><b>Receipt Number</b></td>
      <td>: {{ receipt_number }}</td>
    </tr>
    <tr>
      <td><b>Lorry No</b></td>
      <td>: {{ vehicle_no or "" }}</td>
      <td></td>
      <td></td>
    </tr>
    <tr>
      <td><b>Transport</b></td>
            <td>: {{ frappe.utils.fmt_money(transport_total[0], currency=doc.currency) if transport_total[0] else "" }}</td>
      <td></td>
      <td></td>
    </tr>
  </table>

  <table class="wb-lines">
    <thead>
      <tr>
        <th>TKT</th>
        <th>Description</th>
        <th class="wb-right">Tare</th>
        <th class="wb-right">Gross</th>
        <th class="wb-right">Qty</th>
        <th class="wb-right">Price</th>
        <th class="wb-right">ItemAmt</th>
        <th class="wb-right">Transport</th>
        <th class="wb-right">Amount</th>
        <th class="wb-right">VAT</th>
        <th class="wb-right">Total</th>
      </tr>
    </thead>
    <tbody>
      {% for item in product_items %}
        {% set row_transport = transport_total[0] if loop.first else 0 %}
        {% set row_amount = (item.amount or 0) + row_transport %}

        {% set tax_rate = default_tax_rate or 0 %}
        {% set row_vat = row_amount * tax_rate / 100 %}
        {% set row_total = row_amount + row_vat %}

        <tr>
          <td>{{ wbt.name if wbt else "" }}</td>
          <td>{{ item.item_name or item.description or item.item_code }}</td>
          <td class="wb-right">{{ frappe.format_value((wbt.tare_weight if wbt else 0), {"fieldtype": "Float", "precision": 2}) }}</td>
          <td class="wb-right">{{ frappe.format_value((wbt.gross_weight if wbt else 0), {"fieldtype": "Float", "precision": 2}) }}</td>
          <td class="wb-right">{{ frappe.format_value(item.qty or 0, {"fieldtype": "Float", "precision": 2}) }}</td>
          <td class="wb-right">{{ frappe.utils.fmt_money(item.rate or 0, currency=doc.currency) }}</td>
          <td class="wb-right">{{ frappe.utils.fmt_money(item.amount or 0, currency=doc.currency) }}</td>
          <td class="wb-right">{{ frappe.utils.fmt_money(row_transport, currency=doc.currency) }}</td>
          <td class="wb-right">{{ frappe.utils.fmt_money(row_amount, currency=doc.currency) }}</td>
          <td class="wb-right">{{ frappe.utils.fmt_money(row_vat, currency=doc.currency) }}</td>
          <td class="wb-right">{{ frappe.utils.fmt_money(row_total, currency=doc.currency) }}</td>
        </tr>
      {% endfor %}
    </tbody>
  </table>

  <div class="wb-total">INVOICE TOTAL {{ doc.currency }}: {{ frappe.utils.fmt_money(doc.grand_total, currency=doc.currency) }}</div>

  <div class="wb-terms">
    <b>CONDITIONS OF SALES:</b><br>
    This invoice is due within 30 days prior to the sales.<br>
    Interest at 1.5 % per month may be charged on overdue accounts.<br>
    In case of recovery through an attorney 10 % collection fee will be charged.<br>
    Goods once sold cannot be returned.
  </div>

  <table class="wb-meta" style="margin-top: 10px;">
    <tr>
      <td><b>Customer</b></td>
      <td>: {{ doc.customer_name or "" }}</td>
      <td><b>Selling Clerk</b></td>
      <td>: {{ clerk_name or doc.owner or "" }}</td>
    </tr>
  </table>

  <div class="wb-right" style="margin-top: 20px; font-size: 10px;">
    Created at {{ frappe.format_value(doc.creation, {"fieldtype": "Datetime"}) }}
  </div>
</div>
"}]
